window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["e"]={"Edward": "<b>Edward</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia angielskiego. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">języku staroangielskim</a>:", "Eugeniusz": "<b>Eugeniusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Oznacza „zacny“ lub „szlachetnie urodzony”. Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Eugenia\" target=\"_blank\" rel=\"noopener noreferrer\">Eugenia</a>.", "Emil": "<b>Emil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Emiliusze\" target=\"_blank\" rel=\"noopener noreferrer\">Emiliuszów</a> (<i>Aemilius</i>). Łacińskie słowo <i>aemulor</i> oznacza „rywalizujący”. Patronem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Emil_z_Kordoby\" target=\"_blank\" rel=\"noopener noreferrer\">Emil z Kordoby</a> (†852), męczennik i święty katolicki wspominany 15 września.", "Eryk": "<b>Eryk</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskiego</a>. Nadawane wielu jarlom i królom <a href=\"https://pl.wikipedia.org/wiki/Szwecja\" target=\"_blank\" rel=\"noopener noreferrer\">szwedzkim</a> i <a href=\"https://pl.wikipedia.org/wiki/Dania\" target=\"_blank\" rel=\"noopener noreferrer\">duńskim</a>. Pochodzenie tego imienia podaje się ze staro-wysoko-niemieckiego, gdzie <b>era</b> znaczy: honor, cześć, oraz <b>richi</b> – bogaty. Całość zaś oznacza osobę zasobną w honor lub władcę, który zaszczytnie króluje. Jego popularność sięga czasów króla szwedzkiego Eryka zmarłego w <a href=\"https://pl.wikipedia.org/wiki/1160\" target=\"_blank\" rel=\"noopener noreferrer\">1160</a>. Inne spotykane znaczenie to „wieczny władca” od <i>ei(r)</i> co oznacza w staronordyjskim „wieczny” i <i>ríkr</i> – w staronordyjskim „władca”.", "Edmund": "<b>Edmund</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskiego</a>. Wywodzi się od słowa oznaczającego „zapewniający opiekę”.", "Ernest": "<b>Ernest</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego \"powaga, zapał, walka\". Patronem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Ernest_z_Zwiefalten\" target=\"_blank\" rel=\"noopener noreferrer\">Święty Ernest</a> - opat i <a href=\"https://pl.wikipedia.org/wiki/M%C4%99czennicy_chrze%C5%9Bcija%C5%84scy\" target=\"_blank\" rel=\"noopener noreferrer\">męczennik</a> (zginął w 1148 roku).", "Emanuel": "<b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Erwin": "<b>Erwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe z wyrazów <i>heri</i> – „drużyna wojenna” oraz <i>wini</i> – „przyjaciel”, oznaczające „ten, który chętnie wojuje”. Pojawia się również jako: <b>Ermin</b>, <b>Hermin</b> i <b>Irmin</b>.", "Emilian": "Utarło się kilka <a href=\"https://pl.wikipedia.org/wiki/Zdrobnienie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnień</a> tego imienia: <i>Emko</i>, <i>Mila</i>, <i><a href=\"https://pl.wikipedia.org/wiki/Milan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Milan</a></i>, <i>Milo</i> itp., oraz najpopularniejsze <i><b><a href=\"https://pl.wikipedia.org/wiki/Emil\" target=\"_blank\" rel=\"noopener noreferrer\">Emil</a></b></i>. Ostatnie, dzięki twórczości <a href=\"https://pl.wikipedia.org/wiki/Jean-Jacques_Rousseau\" target=\"_blank\" rel=\"noopener noreferrer\">Jeana-Jacques’a Rousseau</a> (<i><a href=\"https://pl.wikipedia.org/wiki/Emil,_czyli_o_wychowaniu\" target=\"_blank\" rel=\"noopener noreferrer\">Emil, czyli O wychowaniu</a></i>), zostało upowszechnione w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX w.</a> jako odrębne imię i często stosowane wymiennie. Znane <a href=\"https://pl.wikipedia.org/wiki/Spieszczenie\" target=\"_blank\" rel=\"noopener noreferrer\">spieszczenia</a> imienia to m.in.: <i>Jemek</i>, <i>Milek</i>, <i>Miluś</i>, <i>Miłek</i> itp., oraz pochodzące od zdrobnienia <i>Emil</i>: <i>Emilek</i>, <i>Emisz</i>, <i>Emiś</i> itp.", "Edwin": "<b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Eliasz": "<b>Eliasz</b>, również <b>Eliasz z Tiszbe</b> lub <b>Eliasz Tiszbita</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;אֱלִיָּהוּ&#8206; <i>Eliyáhu</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἠλίας <i>Elias</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_cerkiewnos%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">cs.</a>&#160;Илья-пророк) – jeden z <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">proroków</a> <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a> żyjący w IX w. przed Chrystusem w północnym państwie Izraela (imię tłumaczone jako: „Bogiem jest <a href=\"https://pl.wikipedia.org/wiki/Jah\" target=\"_blank\" rel=\"noopener noreferrer\">Jah</a>”, „moim Bogiem jest <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>”). <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ci_i_b%C5%82ogos%C5%82awieni_Ko%C5%9Bcio%C5%82a_katolickiego\" target=\"_blank\" rel=\"noopener noreferrer\">Święty Kościoła katolickiego</a>, <a href=\"https://pl.wikipedia.org/wiki/Cerkiew_prawos%C5%82awna\" target=\"_blank\" rel=\"noopener noreferrer\">prawosławnego</a>, <a href=\"https://pl.wikipedia.org/wiki/Koptyjski_Ko%C5%9Bci%C3%B3%C5%82_Ortodoksyjny\" target=\"_blank\" rel=\"noopener noreferrer\">koptyjskiego</a>, <a href=\"https://pl.wikipedia.org/wiki/Apostolski_Ko%C5%9Bci%C3%B3%C5%82_Ormia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ormiańskiego</a> i <a href=\"https://pl.wikipedia.org/wiki/Syryjski_Ko%C5%9Bci%C3%B3%C5%82_Ortodoksyjny\" target=\"_blank\" rel=\"noopener noreferrer\">syryjskiego</a>.", "Eligiusz": "<b>Eligiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> czasownika <i>eligo, elegi, electum</i> oznaczające – „wybrany”.", "Edgar": "<b>Edgar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia staroangielskiego/germańskiego. Wywodzi się od staroangielskich ěad (majątek, bogactwo, szczęście), gard (obrońca, stróż) lub od germańskiego ed- (posiadanie, dziedzictwo). Oznacza: stróż, obrońca własności.", "Ewald": "<b>Ewald</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się ze złożenia słów <i>eo</i> – „prawo” i <i>wald</i> – „rządzić”, „panować”. Jego znaczenie można interpretować jako „panujący sprawiedliwie, w zgodzie z prawem”. Patronami tego imienia są bracia św. Ewald Biały i św. Ewald Czarny (<a href=\"https://pl.wikipedia.org/wiki/VII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VII wiek</a>), wspominani 3 października.", "Euzebiusz": "<b>Euzebiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> <i>eusébeios</i>. Pierwotnie przymiotnik ten użyty został dla określenia jednego z miesięcy na cześć cesarza rzymskiego <a href=\"https://pl.wikipedia.org/wiki/Antoninus_Pius\" target=\"_blank\" rel=\"noopener noreferrer\">Antonina Piusa</a>. Wywodzi się od słowa oznaczającego „bogobojny”, „święty”.", "Emmanuel": "<b>Emmanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Symbol\" target=\"_blank\" rel=\"noopener noreferrer\">symboliczne</a> imię (z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i> 'immanu 'el</i> – <i>Bóg jest z nami</i>), przypisywane przez <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">proroka</a> <a href=\"https://pl.wikipedia.org/wiki/Izajasz\" target=\"_blank\" rel=\"noopener noreferrer\">Izajasza</a> chłopcu, którego królowi <a href=\"https://pl.wikipedia.org/wiki/Achaz\" target=\"_blank\" rel=\"noopener noreferrer\">Achazowi</a> miała urodzić młoda kobieta (<a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Izajasza\" target=\"_blank\" rel=\"noopener noreferrer\">Iz</a> 7,14) w momencie poważnego zagrożenia dynastii. W chwili wygłoszenia proroctwa król <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Damaszku\" target=\"_blank\" rel=\"noopener noreferrer\">Damaszku</a>, <a href=\"https://pl.wikipedia.org/wiki/Resin\" target=\"_blank\" rel=\"noopener noreferrer\">Resin</a>, i król <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Izraela_(pa%C5%84stwo_p%C3%B3%C5%82nocne)\" target=\"_blank\" rel=\"noopener noreferrer\">Izraela</a>, <a href=\"https://pl.wikipedia.org/wiki/Pekach\" target=\"_blank\" rel=\"noopener noreferrer\">Pekach</a>, oblegli Jerozolimę w ramach toczącej się <a href=\"https://pl.wikipedia.org/wiki/Wojna_syro-efraimska\" target=\"_blank\" rel=\"noopener noreferrer\">wojny syro-efraimskiej</a>. Emmanuel miał być znakiem Bożej łaski wobec Achaza, skutkującej niepowodzeniem koalicji.", "Ewaryst": "<b>Ewaryst</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, które oznacza <i>miły, przyjemny, najlepszy</i>. Imię to nadawane jest w Polsce co najmniej od <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVII</a> w. Istnieje kilku świętych Ewarystów, m.in. <a href=\"https://pl.wikipedia.org/wiki/Ewaryst_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">Ewaryst, papież</a> oraz św. Ewaryst z Konstantynopola.", "Engelbert": "<b>Engelbert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od nazwy jednego z plemion germańskich <i>Angil</i> (<a href=\"https://pl.wikipedia.org/wiki/Anglowie\" target=\"_blank\" rel=\"noopener noreferrer\">Anglowie</a>) połączonego słowem <i>beraht</i> oznaczającym \"jasny\".", "Erich": "<b>Eryk</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskiego</a>. Nadawane wielu jarlom i królom <a href=\"https://pl.wikipedia.org/wiki/Szwecja\" target=\"_blank\" rel=\"noopener noreferrer\">szwedzkim</a> i <a href=\"https://pl.wikipedia.org/wiki/Dania\" target=\"_blank\" rel=\"noopener noreferrer\">duńskim</a>. Pochodzenie tego imienia podaje się ze staro-wysoko-niemieckiego, gdzie <b>era</b> znaczy: honor, cześć, oraz <b>richi</b> – bogaty. Całość zaś oznacza osobę zasobną w honor lub władcę, który zaszczytnie króluje. Jego popularność sięga czasów króla szwedzkiego Eryka zmarłego w <a href=\"https://pl.wikipedia.org/wiki/1160\" target=\"_blank\" rel=\"noopener noreferrer\">1160</a>. Inne spotykane znaczenie to „wieczny władca” od <i>ei(r)</i> co oznacza w staronordyjskim „wieczny” i <i>ríkr</i> – w staronordyjskim „władca”.", "Enzo": "<b>Wincenty</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>vincens</em> – zwyciężający) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>.", "Erhard": "<b>Erhard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>era</i> - \"honor\", lub \"respekt\" i <i>hard</i> - \"dzielny\".", "Eustachy": "<b>Eustachy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, którego znaczenie można objaśnić jako „kwitnący”, „płodny”. Imię to nosił męczennik <a href=\"https://pl.wikipedia.org/wiki/Eustachy_Rzymski\" target=\"_blank\" rel=\"noopener noreferrer\">Eustachy Rzymski</a>, święty Kościoła katolickiego i prawosławnego.", "Egon": "<b>Egon</b> – imię męskie, alternatywna forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Egbert_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Egbert</a>.", "Erazm": "<b>Erazm</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „miły”, „uprzejmy”. W dawnych źródłach mazowieckich Erazm pojawia się jako zamiennik męskiego imienia słowiańskiego <i><b><a href=\"https://pl.wikipedia.org/wiki/Niemir\" target=\"_blank\" rel=\"noopener noreferrer\">Niemierza</a></b></i>.", "Elvis": "<b>Elvis</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">staroangielskiego</a> <i>Eall-wis</i>, czyli <i>mądrego</i>. Staroangielskie akcentowane „a” często przechodzi w „e”, a więc <i>Alvis</i> → <i>Elvis</i>. Czasami w wyjaśnieniach <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">etymologii</a> imienia alternatywne podaje się, że pochodzi ono od <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwiska</a> <i>Elwes</i>, a wiążąc ją z nazwą <i>Alwyn</i>.", "Eitan": "Eitan został przedstawiony jako następca używanego obecnie w izraelskiej armii zmodyfikowanego, <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">amerykańskiego</a> transportera <a href=\"https://pl.wikipedia.org/wiki/M113\" target=\"_blank\" rel=\"noopener noreferrer\">M-113 Zelda</a>, a także kołowy odpowiednik transportera gąsienicowego <a href=\"https://pl.wikipedia.org/wiki/Namer\" target=\"_blank\" rel=\"noopener noreferrer\">Namer</a>.", "Eliezer": "Jego imię znaczy „Bóg mego ojca był dla mnie pomocą”. Główny sługa <a href=\"https://pl.wikipedia.org/wiki/Abraham\" target=\"_blank\" rel=\"noopener noreferrer\">Abrahama</a>, który miał po nim dziedziczyć, gdy Abraham nie miał potomka. Najprawdopodobniej to Eliezerowi powierzono misję udania się do <a href=\"https://pl.wikipedia.org/wiki/Mezopotamia\" target=\"_blank\" rel=\"noopener noreferrer\">Mezopotamii</a> po żonę dla <a href=\"https://pl.wikipedia.org/wiki/Izaak\" target=\"_blank\" rel=\"noopener noreferrer\">Izaaka</a>.", "Eliot": "<b>Eliot</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Eliyahu</i>, oznaczającego <i>„Mój Bóg jest Panem”</i>.", "Elian": "Do jego głównych dzieł należą: <i>De natura animalium</i> (<i>Περὶ ζῴων ἰδιότητος</i>) i <i>Varia historia</i> (<i>Ποικίλη ἱστορία</i>) czyli <i>O właściwościach zwierząt</i> i <i>Opowiastki rozmaite</i>. Pierwsze to opowieści o niezwykłych cechach i zaletach zwierząt, zawarte w 17 księgach, drugie to ujęte w 14 księgach anegdoty historyczne i przyrodnicze pochodzące z zaginionej literatury wcześniejszej. Oprócz szerokiej wiedzy tematycznej dają one wgląd w zakres poznania świata grecko-rzymskiego. Elian jest ponadto autorem zbioru 20 utworów <a href=\"https://pl.wikipedia.org/wiki/Epistolografia\" target=\"_blank\" rel=\"noopener noreferrer\">epistolarnych</a>, zatytułowanego <i>Listy wieśniaków</i> (<i>Epistulae rusticae</i>, gr. <i>Ἐπιστολαὶ ἀγροικικαί</i>), mającego szczególną wartość dzięki licznym cytatom z niezachowanych dzieł starszych autorów. Za zaginione uważa się jego niektóre pisma o charakterze filozoficznym (np. o opatrzności) oraz <a href=\"https://pl.wikipedia.org/wiki/Pamflet\" target=\"_blank\" rel=\"noopener noreferrer\">pamflet</a> na Heliogabala.", "Eberhard": "<b>Eberhard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Powstało z od połączenia starogermańskich słów <i>eber</i> – \"dzik\" i <i>hard</i> – \"dzielny\".", "Elizeusz": "<b>Elizeusz</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;אֱלִישָׁע‎&#8206; – <i>Elišaʿ</i> lub <i>ʾĔlîšaʿ</i> oznaczające „<i>Bóg wybawił; Bóg jest wybawieniem</i>”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_cerkiewnos%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">cs.</a>&#160;Елисей) – <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a> <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijny</a>, uczeń <a href=\"https://pl.wikipedia.org/wiki/Eliasz\" target=\"_blank\" rel=\"noopener noreferrer\">Eliasza</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ci_i_b%C5%82ogos%C5%82awieni_Ko%C5%9Bcio%C5%82a_katolickiego\" target=\"_blank\" rel=\"noopener noreferrer\">święty katolicki</a> i <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ci_prawos%C5%82awni\" target=\"_blank\" rel=\"noopener noreferrer\">prawosławny</a>, wspominany w wielu innych <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bcio%C5%82y_wschodnie\" target=\"_blank\" rel=\"noopener noreferrer\">Kościołach wschodnich</a>.", "Efraim": "Młodszy z dwóch synów <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Józefa</a> i <a href=\"https://pl.wikipedia.org/wiki/Asenat\" target=\"_blank\" rel=\"noopener noreferrer\">Asenat</a>, urodzony w <a href=\"https://pl.wikipedia.org/wiki/Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">Egipcie</a>. <a href=\"https://pl.wikipedia.org/wiki/Jakub_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakub</a> zaadoptował Efraima, swego wnuka, i swoje błogosławieństwo dał jemu, a nie jego starszemu bratu <a href=\"https://pl.wikipedia.org/wiki/Manasses_(syn_J%C3%B3zefa)\" target=\"_blank\" rel=\"noopener noreferrer\">Manassesowi</a>. Początkowo miał dziewięciu synów: Szutelacha, Bereda, Tachata, Eleadę, Tachata, Zabada, Szutelacha, Ezera oraz Eleada. Wszyscy oni zostali jednak zabici. Po tym wydarzeniu urodził się jeszcze tylko jeden syn Efraima, a imię, które zostało mu nadane, to Beria. Od Efraima wywodzi się ważne pokolenie. Prorocy nazywają czasem jego imieniem <a href=\"https://pl.wikipedia.org/wiki/Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">Izrael</a>. Pojawia się w <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Księdze Rodzaju 41, 52; 48</a>.", "Eustachiusz": "<b>Eustachiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słów <i>eu</i> \"dobrze\" oraz <i>stáchys</i> \"owoc\", sens imienia można objaśniać jako \"płodny, kwitnący\". Oboczna męska forma: <a href=\"https://pl.wikipedia.org/wiki/Eustachy\" target=\"_blank\" rel=\"noopener noreferrer\">Eustachy</a>.", "Ekspedyt": "<b>Ekspedyt</b>, <b>Wierzyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od czasownika <em>expediō, expedīre</em> („uwolnić, wyzwolić z więzów”), <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>expedītus</em> znaczy „uwolniony, lekko ubrany, lekkozbrojny; szybki, zwinny”. Imię to zostało w Polsce przetłumaczone jako <b>Wierzyn</b> („ten, któremu można wierzyć”). Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Ekspedyt\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Ekspedyt</a>.", "Emiliusz": "<b>Emil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Emiliusze\" target=\"_blank\" rel=\"noopener noreferrer\">Emiliuszów</a> (<i>Aemilius</i>). Łacińskie słowo <i>aemulor</i> oznacza „rywalizujący”. Patronem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Emil_z_Kordoby\" target=\"_blank\" rel=\"noopener noreferrer\">Emil z Kordoby</a> (†852), męczennik i święty katolicki wspominany 15 września.", "Ernestyn": "<b>Ernest</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego \"powaga, zapał, walka\". Patronem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Ernest_z_Zwiefalten\" target=\"_blank\" rel=\"noopener noreferrer\">Święty Ernest</a> - opat i <a href=\"https://pl.wikipedia.org/wiki/M%C4%99czennicy_chrze%C5%9Bcija%C5%84scy\" target=\"_blank\" rel=\"noopener noreferrer\">męczennik</a> (zginął w 1148 roku).", "Eko": "<b>Eko</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>) – w japońskim <a href=\"https://pl.wikipedia.org/wiki/Buddyzm\" target=\"_blank\" rel=\"noopener noreferrer\">buddyzmie</a> ofiarowanie zasług recytowane po śpiewach jednej lub kilku <a href=\"https://pl.wikipedia.org/wiki/Sutra\" target=\"_blank\" rel=\"noopener noreferrer\">sutr</a> albo <a href=\"https://pl.wikipedia.org/wiki/Dharani\" target=\"_blank\" rel=\"noopener noreferrer\">dharani</a>. Eko dosłownie oznacza \"zwrot w kierunku\" i jest ofiarowaniem <a href=\"https://pl.wikipedia.org/wiki/Pole_zas%C5%82ug\" target=\"_blank\" rel=\"noopener noreferrer\">zasług</a> zyskanych poprzez <a href=\"https://pl.wikipedia.org/wiki/Samadhi\" target=\"_blank\" rel=\"noopener noreferrer\">samadhi</a> śpiewu <a href=\"https://pl.wikipedia.org/wiki/Sutra\" target=\"_blank\" rel=\"noopener noreferrer\">sutr</a> i <a href=\"https://pl.wikipedia.org/wiki/Dharani\" target=\"_blank\" rel=\"noopener noreferrer\">dharani</a> wszystkim <a href=\"https://pl.wikipedia.org/wiki/Budda\" target=\"_blank\" rel=\"noopener noreferrer\">buddom</a>, <a href=\"https://pl.wikipedia.org/wiki/Bodhisattwa\" target=\"_blank\" rel=\"noopener noreferrer\">bodhisattwom</a>, <a href=\"https://pl.wikipedia.org/wiki/Patriarcha\" target=\"_blank\" rel=\"noopener noreferrer\">patriarchom</a> oraz innym <a href=\"https://pl.wikipedia.org/wiki/Czuj%C4%85ce_istoty\" target=\"_blank\" rel=\"noopener noreferrer\">czującym istotom</a>.", "Eckhard": "<b>Ekhard</b>, <b>Jakert</b>, <b>Eghard</b>, <b>Ekard</b>, <b>Ekehard</b>, <i><b>Hekard</b></i>, <i><b>Hekehard</b></i>, <i><b>Hekhard</b></i> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, występujące w Polsce od średniowiecza. Pierwszy człon tego imienia najprawdopodobniej oznacza „ostrze, szpica”, a jego forma podstawowa to <i>eg(g)i</i>, <i>ek(k)i</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gocki\" target=\"_blank\" rel=\"noopener noreferrer\">goc.</a> <i>Agja</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starosakso%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">stsas.</a> <i>eggia</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">stwniem.</a> <i>egga</i>, <i>ecka</i> — „kąt, kant, ostrze jakiejś broni, miecz”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_%C5%9Brednio-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">śrwniem.</a> <i>ecke</i>, <i>egge</i> — „ostrze broni, kąt, kant”); może być to jednak także <i>egi</i> (goc. <i>agis</i>, stwniem. <i>āgi</i>, <i>ēgi</i> — „strach, trwoga”). Drugi człon to <i>hart</i>, <i>hard</i> — „silny, mocny, krzepki, dzielny”. Imię to było w Polsce zapisywane w formach wymienionych powyżej. Możliwe zdrobnienia: Hekiel, Hekosz.", "Efrem": "<b>Efrem</b>, <b>Efraim</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od hebrajskiego słowa <i>Ephrayim</i> oznaczającego „przynoszący dobry owoc”. W <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a> był synem Józefa i <a href=\"https://pl.wikipedia.org/wiki/Asenat\" target=\"_blank\" rel=\"noopener noreferrer\">Asenat</a>, twórcą jednego z plemion Izraela. Ogłoszono siedmiu świętych o tym imieniu.", "Emeryk": "<b>Emeryk</b>, Amalaryk, Amalryk – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się ze starogermańskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Amalaryk\" target=\"_blank\" rel=\"noopener noreferrer\">Amalaryk</a>, oznaczającego „władca <a href=\"https://pl.wikipedia.org/wiki/Amalowie\" target=\"_blank\" rel=\"noopener noreferrer\">Amalów</a>” (Amalowie według gockiej legendy to ród królewski pochodzenia boskiego). Człon <i>amal</i> może także oznaczać „gorliwy” lub „dzielny, aktywny”. Emeryk może wywodzić się również z saksońskiego <i>Emmerich</i>, oznaczającego „zawsze bogaty”.", "Earl": "<b>Earl</b> – najstarszy i pierwotnie najwyższy <a href=\"https://pl.wikipedia.org/wiki/Anglia\" target=\"_blank\" rel=\"noopener noreferrer\">brytyjski</a> tytuł <a href=\"https://pl.wikipedia.org/wiki/Feudalizm\" target=\"_blank\" rel=\"noopener noreferrer\">feudalny</a>, następnie arystokratyczny. Samo słowo wywodzi się ze skandynawskiego <b><a href=\"https://pl.wikipedia.org/wiki/Jarl\" target=\"_blank\" rel=\"noopener noreferrer\">jarl</a></b> (pierwotnie znaczyło to po prostu <i>człowiek możny</i>, <i>potężny</i>, <i>bogaty</i>, później było tytułem wodzów drużyny zbrojnej, namiestników królewskich, zarządców prowincji. W <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a> w <a href=\"https://pl.wikipedia.org/wiki/Szwecja\" target=\"_blank\" rel=\"noopener noreferrer\">Szwecji</a> był to tytuł najwyższego urzędnika państwa). <a href=\"https://pl.wikipedia.org/wiki/Encyklopedia_Britannica\" target=\"_blank\" rel=\"noopener noreferrer\">Encyclopædia Britannica</a> wywodzi ten tytuł również od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starofrancuski\" target=\"_blank\" rel=\"noopener noreferrer\">starofrancuskiego</a> <i>eorl</i>, oznaczającego <i>szlachcica</i>, <i>wojownika</i>. Wprowadzony w <a href=\"https://pl.wikipedia.org/wiki/Anglia\" target=\"_blank\" rel=\"noopener noreferrer\">Anglii</a> w <a href=\"https://pl.wikipedia.org/wiki/XI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XI w.</a> po najeździe duńskim w miejsce wcześniej używanego tytułu <a href=\"https://pl.wikipedia.org/wiki/Ealdorman\" target=\"_blank\" rel=\"noopener noreferrer\">Ealdormana</a>. Kontynentalnym odpowiednikiem earla jest <i><a href=\"https://pl.wikipedia.org/wiki/Hrabia\" target=\"_blank\" rel=\"noopener noreferrer\">hrabia</a></i> (tłumaczony w jęz. ang. jako <i>count</i>, <i>counte</i>).", "Egbert": "<b>Egbert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia germańskiego. Oznacza „błyszczący jak miecz”. Jego patronem jest <a href=\"https://pl.wikipedia.org/wiki/Egbert_(%C5%9Bwi%C4%99ty)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Egbert</a>, <a href=\"https://pl.wikipedia.org/wiki/Benedyktyni\" target=\"_blank\" rel=\"noopener noreferrer\">benedyktyn</a> z przełomu VII i VIII w. <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>", "Elon": "<b>Elon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> אֵילֹן) – postać <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijna</a>, według <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_S%C4%99dzi%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Sędziów</a> (Sdz 12,11-12) dziesiąty <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziowie_(Biblia)\" target=\"_blank\" rel=\"noopener noreferrer\">sędzia</a> <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">Izraela</a>. Pochodził z plemienia <a href=\"https://pl.wikipedia.org/wiki/Zabulon\" target=\"_blank\" rel=\"noopener noreferrer\">Zebulona</a>, objął rządy po śmierci <a href=\"https://pl.wikipedia.org/wiki/Ibsan\" target=\"_blank\" rel=\"noopener noreferrer\">Ibsana</a>. Panował przez dziesięć lat. Po śmierci został pochowany w Ajjalonie na terytorium Zebulonitów, utożsamianym z Chirbet el-Lon w <a href=\"https://pl.wikipedia.org/wiki/Galilea\" target=\"_blank\" rel=\"noopener noreferrer\">Galilei</a>. Jego następcą został <a href=\"https://pl.wikipedia.org/wiki/Abdon_(s%C4%99dzia)\" target=\"_blank\" rel=\"noopener noreferrer\">Abdon</a>.", "Ezio": "<b>Aecjusz</b> – męskie imię łacińskie. Prawdopodobnie pochodzi od greckiego słowa αετος (Aetos), znaczącego \"orzeł\".", "Ezdrasz": "<b>Ezdrasz</b> – <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijne</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Wywodzi się od hebr. <i>ezrā</i>, <i>ezrāh</i> – „[Bóg jest] pomocą”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aram.</a> <i>ezrā</i> – „pomoc”. Po raz pierwszy w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> imię to zostało zanotowane w <a href=\"https://pl.wikipedia.org/wiki/XIV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIV wieku</a> w formie <i>Esdras</i>.", "Enoch": "<b>Enoch</b> (lub <b>Henoch</b>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od hebrajskiego imienia <i>Chanok</i>, oznaczającego „pełny poświęcenia”.", "El": "Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Elwir": "<b>Elwir</b> – imię męskie, wywodzące się od imienia <a href=\"https://pl.wikipedia.org/wiki/Elwira\" target=\"_blank\" rel=\"noopener noreferrer\">Elwira</a>, jako jego męski odpowiednik.", "Emilia": "Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Emil\" target=\"_blank\" rel=\"noopener noreferrer\">Emil</a>, <a href=\"https://pl.wikipedia.org/wiki/Emilian\" target=\"_blank\" rel=\"noopener noreferrer\">Emilian</a>.", "Eka": "<b>Eka</b> – w <a href=\"https://pl.wikipedia.org/wiki/Gwara_pozna%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">gwarze poznańskiej</a> miejska grupa koleżeńska pochodząca z jednej dzielnicy lub okolicy; także powiązana terytorialnie grupa złodziejska.", "Ekard": "<b>Ekhard</b>, <b>Jakert</b>, <b>Eghard</b>, <b>Ekard</b>, <b>Ekehard</b>, <i><b>Hekard</b></i>, <i><b>Hekehard</b></i>, <i><b>Hekhard</b></i> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, występujące w Polsce od średniowiecza. Pierwszy człon tego imienia najprawdopodobniej oznacza „ostrze, szpica”, a jego forma podstawowa to <i>eg(g)i</i>, <i>ek(k)i</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gocki\" target=\"_blank\" rel=\"noopener noreferrer\">goc.</a> <i>Agja</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starosakso%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">stsas.</a> <i>eggia</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">stwniem.</a> <i>egga</i>, <i>ecka</i> — „kąt, kant, ostrze jakiejś broni, miecz”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_%C5%9Brednio-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">śrwniem.</a> <i>ecke</i>, <i>egge</i> — „ostrze broni, kąt, kant”); może być to jednak także <i>egi</i> (goc. <i>agis</i>, stwniem. <i>āgi</i>, <i>ēgi</i> — „strach, trwoga”). Drugi człon to <i>hart</i>, <i>hard</i> — „silny, mocny, krzepki, dzielny”. Imię to było w Polsce zapisywane w formach wymienionych powyżej. Możliwe zdrobnienia: Hekiel, Hekosz.", "Eweryst": "<b>Ewaryst</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, które oznacza <i>miły, przyjemny, najlepszy</i>. Imię to nadawane jest w Polsce co najmniej od <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVII</a> w. Istnieje kilku świętych Ewarystów, m.in. <a href=\"https://pl.wikipedia.org/wiki/Ewaryst_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">Ewaryst, papież</a> oraz św. Ewaryst z Konstantynopola.", "Ennio": "<b>Enniusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od nazwy rodu <i>Enniuszów</i>.", "Ed": "gdzie n1, n2 określają wiersz lub zakres wierszy, na których operuje polecenie. Specjalny symbol $ oznacza ostatni wiersz i np. polecenie <b>1,$p</b> spowoduje wyświetlenie wszystkich wierszy.", "Erast": "<b>Erast</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Pochodzi od greckiego imienia <i>Erastus</i> oznaczającego \"miły\". Było imieniem pomocnika <a href=\"https://pl.wikipedia.org/wiki/Pawe%C5%82_z_Tarsu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Pawła</a> wymienionego w <a href=\"https://pl.wikipedia.org/wiki/Dzieje_Apostolskie\" target=\"_blank\" rel=\"noopener noreferrer\">Dziejach Apostolskich</a> <a href=\"https://pl.wikipedia.org/wiki/Erast_z_Koryntu\" target=\"_blank\" rel=\"noopener noreferrer\">Erasta z Koryntu</a>.", "Ekhard": "<b>Ekhard</b>, <b>Jakert</b>, <b>Eghard</b>, <b>Ekard</b>, <b>Ekehard</b>, <i><b>Hekard</b></i>, <i><b>Hekehard</b></i>, <i><b>Hekhard</b></i> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, występujące w Polsce od średniowiecza. Pierwszy człon tego imienia najprawdopodobniej oznacza „ostrze, szpica”, a jego forma podstawowa to <i>eg(g)i</i>, <i>ek(k)i</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gocki\" target=\"_blank\" rel=\"noopener noreferrer\">goc.</a> <i>Agja</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starosakso%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">stsas.</a> <i>eggia</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">stwniem.</a> <i>egga</i>, <i>ecka</i> — „kąt, kant, ostrze jakiejś broni, miecz”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_%C5%9Brednio-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">śrwniem.</a> <i>ecke</i>, <i>egge</i> — „ostrze broni, kąt, kant”); może być to jednak także <i>egi</i> (goc. <i>agis</i>, stwniem. <i>āgi</i>, <i>ēgi</i> — „strach, trwoga”). Drugi człon to <i>hart</i>, <i>hard</i> — „silny, mocny, krzepki, dzielny”. Imię to było w Polsce zapisywane w formach wymienionych powyżej. Możliwe zdrobnienia: Hekiel, Hekosz.", "Emer": "Dała mu wiele trudnych zadań do wykonania, bo bardzo chciał spędzić z nią noc. Uważała, że skoro jest bardzo piękna, to jest tego warta. Cuchulainn przystał na jej warunki. W innej wersji, w pochodzącej z <a href=\"https://pl.wikipedia.org/wiki/VIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">ósmego wieku</a> <i>Bricriu's Feast</i>, została ona ukazana jako żona Cuchulainna o imieniu Eimher Pięknowłosa (ang. <i>Eimher of the Beautiful Hair</i>) i córka Forghalla Zwinnego (ang. <i>Forghall the Dexterous</i>). W tej wersji mitu Cuchulainn ujrzał ją po raz pierwszy w czasie swego pobytu na dworze najwyższego króla Irlandii w Tarze. Ojciec Emer, naczelnik klanu Meathu był przeciwny małżeństwu. Aby się go pozbyć nakazał mu wyruszyć w podróż w celu udoskonalenia rzemiosła wojennego i po jego powrocie miał dopiero rozważyć czy Cuchulainn będzie mógł zostać jego zięciem. Cuchulainn sprostał wyzwaniu i powrócił po rękę dziewczyny. Zanim doszło do zaręczyn bohater musiał przejść jeszcze jedną próbę - zaatakować potężnie ufortyfikowany zamek Fogalla. Emer była zakochana bez pamięci w swoim przystojnym mężu, ale w ich małżeństwie także nie brakowało kłopotów, gdyż ulsterski bohater podobał się wielu kobietom. Przed ostatnią bitwą Cuchulainna z królową <a href=\"https://pl.wikipedia.org/wiki/Medb\" target=\"_blank\" rel=\"noopener noreferrer\">Medb</a>, Emer próbowała przekonać męża aby pozostał w zamku Emain Macha, siedzibie króla <a href=\"https://pl.wikipedia.org/wiki/Conchobar_III_mac_Nessa\" target=\"_blank\" rel=\"noopener noreferrer\">Conchobara MacNessy</a> i nie wyruszał samotnie do boju. Wsiadł na rydwan myśląc ciągle o prośbie swojej ukochanej jednak wrogie mu wiedźmy, córki <a href=\"https://pl.wikipedia.org/wiki/Calatin\" target=\"_blank\" rel=\"noopener noreferrer\">Calatina</a> rzuciły na niego czar, który uniemożliwiał podjęcie mu innej decyzji.", "Eiji": "<b>Eiji</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;えいじ, エイジ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Etem": "<b>Etem</b> (<a href=\"https://pl.wikipedia.org/wiki/Alfabet_deseret\" target=\"_blank\" rel=\"noopener noreferrer\">deseret</a> 𐐀𐐛𐐇𐐣) – w wierzeniach <a href=\"https://pl.wikipedia.org/wiki/Ruch_%C5%9Bwi%C4%99tych_w_dniach_ostatnich\" target=\"_blank\" rel=\"noopener noreferrer\">ruchu świętych w dniach ostatnich</a> (mormonów) <a href=\"https://pl.wikipedia.org/wiki/Jeredyci\" target=\"_blank\" rel=\"noopener noreferrer\">jeredycki</a> król, syn Ahaha. Informacje na jego temat zawiera będąca częścią mormońskiej świętej księgi Księga Etera. Jego panowanie przynależy do późnego okresu jeredyckiej historii. Miało być naznaczone niegodziwością oraz działalnością proroków nawołujących do pokuty, trwało też do śmierci Etema. Władca jest obiektem spekulacji teologicznych, bywa też wykorzystywany przez mormońskich apologetów. Imię Etem występuje wśród wyznających mormonizm <a href=\"https://pl.wikipedia.org/wiki/Maorysi\" target=\"_blank\" rel=\"noopener noreferrer\">Maorysów</a>.", "Epifaniusz": "<b>Epifaniusz</b>, <b>Epifani</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „objawienie się, ukazanie się bóstwa”, „ten, który przyszedł na świat”. Jego żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Epifania_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Epifania</a>.", "Eulogiusz": "<b>Eulogiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wśród patronów – św. Eulogiusz z <a href=\"https://pl.wikipedia.org/wiki/Tarragona\" target=\"_blank\" rel=\"noopener noreferrer\">Tarragony</a>, diakon, spalony na stosie w <a href=\"https://pl.wikipedia.org/wiki/259\" target=\"_blank\" rel=\"noopener noreferrer\">259</a>, św. Eulogiusz, <a href=\"https://pl.wikipedia.org/wiki/Biskup\" target=\"_blank\" rel=\"noopener noreferrer\">biskup</a> <a href=\"https://pl.wikipedia.org/wiki/%C5%9Eanl%C4%B1urfa\" target=\"_blank\" rel=\"noopener noreferrer\">Edessy</a> (zm. w <a href=\"https://pl.wikipedia.org/wiki/383\" target=\"_blank\" rel=\"noopener noreferrer\">383</a>), św. <a href=\"https://pl.wikipedia.org/wiki/Eulogiusz_z_Kordoby\" target=\"_blank\" rel=\"noopener noreferrer\">Eulogiusz z Kordoby</a>, męczennik, ścięty w <a href=\"https://pl.wikipedia.org/wiki/859\" target=\"_blank\" rel=\"noopener noreferrer\">859</a>, a także św. <a href=\"https://pl.wikipedia.org/wiki/Eulogiusz_Aleksandryjski\" target=\"_blank\" rel=\"noopener noreferrer\">Eulogiusz Aleksandryjski</a>, patriarcha Aleksandrii, zm. w <a href=\"https://pl.wikipedia.org/wiki/608\" target=\"_blank\" rel=\"noopener noreferrer\">608</a>.", "E": "<b>E</b> (<a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>e</b>) – piąta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>, siódma litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu polskiego</a>. Zazwyczaj oznacza <a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska\" target=\"_blank\" rel=\"noopener noreferrer\">samogłoskę</a> [<a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_p%C3%B3%C5%82przymkni%C4%99ta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">e</a>] lub [<a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_p%C3%B3%C5%82otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">ɛ</a>].", "Eckard": "<b>Eckard</b> – imię męskie pochodzenia germańskiego. Forma pokrewna imienia <a href=\"https://pl.wikipedia.org/wiki/Ekhard\" target=\"_blank\" rel=\"noopener noreferrer\">Ekkehard</a>.", "Eri": "<b>Eri</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;えり, エリ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Eustazjusz": "<b>Eustacjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>Eustáthios</i>, przejęte do <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a> jako Eustathius i Eustatius, utworzone od przymiotnika eustathés 'silny, dobrze zbudowany, zdrowy'. Mylone z <a href=\"https://pl.wikipedia.org/wiki/Eustachy\" target=\"_blank\" rel=\"noopener noreferrer\">Eustachym</a>. Imię to nosiło niewielu świętych. Jego ukraińskim odpowiednikiem jest <i><b>Ostap</b></i>.", "Eustazy": "<b>Eustazy</b>, <b>Eustazjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, którego pierwszym członem jest <i>eu-</i> (\"dobrze\"), a drugim – <i>stás(is)</i> (\"staranie, trwanie, wytrwałość\").", "Erlin": "Populacja gminy Erlin w 2016 roku liczyła 51&#160;516 mieszkańców – 24&#160;983 kobiety i 26&#160;533 mężczyzn. Liczba gospodarstw domowych wynosiła 14&#160;974, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 3,44 osób.", "Erika": "<b>Eryka</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Eryk\" target=\"_blank\" rel=\"noopener noreferrer\">Eryk</a>, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>.", "Emi": "W lutym 2010 w mediach pojawiły się informacje, że EMI z powodu długów sprzeda legendarne <a href=\"https://pl.wikipedia.org/wiki/Abbey_Road_Studios\" target=\"_blank\" rel=\"noopener noreferrer\">studio Abbey Road</a>, w którym nagrywali między innymi <a href=\"https://pl.wikipedia.org/wiki/The_Beatles\" target=\"_blank\" rel=\"noopener noreferrer\">The Beatles</a>.", "Esmeralda": "<b>Esmeralda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"szmaragd\". Patronem tego imienia jest św. Smaragd (Szmaragd), wspominany razem ze <a href=\"https://pl.wikipedia.org/wiki/Cyriak_Rzymianin\" target=\"_blank\" rel=\"noopener noreferrer\">św. Cyriakiem</a> i <a href=\"https://pl.wikipedia.org/wiki/Largus\" target=\"_blank\" rel=\"noopener noreferrer\">Largusem</a>.", "Eliud": "Jego imię znaczy \"Mój Bóg jest dostojeństwem\", lub \"Bóg dostojeństwa\".", "Eufemiusz": "<b>Eufemiusz</b>, <b>Eufemian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „pomyślnie wróżący”, „przychylny”.", "Eustathios": "<b>Eustacjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>Eustáthios</i>, przejęte do <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a> jako Eustathius i Eustatius, utworzone od przymiotnika eustathés 'silny, dobrze zbudowany, zdrowy'. Mylone z <a href=\"https://pl.wikipedia.org/wiki/Eustachy\" target=\"_blank\" rel=\"noopener noreferrer\">Eustachym</a>. Imię to nosiło niewielu świętych. Jego ukraińskim odpowiednikiem jest <i><b>Ostap</b></i>.", "Euchariusz": "<b>Euchariusz</b>, <b>Eucheriusz</b> (<i>Eucharius</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Oznacza „przyjazny”. Patronem imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Euchariusz_z_Trewiru\" target=\"_blank\" rel=\"noopener noreferrer\">Euchariusz</a>, który był pierwszym biskupem <a href=\"https://pl.wikipedia.org/wiki/Trewir\" target=\"_blank\" rel=\"noopener noreferrer\">Trewiru</a> pod koniec III wieku.", "Enlil": "Według jednego z mitów Enlil stworzył pierwszego człowieka wykopując motyką dziurę w ziemi, z której człowiek wyrósł jak roślina. Inny mit opowiada, jak Enlil rozdziela swych rodziców: Niebo (An) zostaje podniesiony w górę, a Matka Ziemia (Ki) pozostaje przy jego boku. Miał również zesłać potop na Ziemię, aby uciszyć ludzi, przez których nie mógł spać. Jedynymi, którzy przetrwali potop, byli <a href=\"https://pl.wikipedia.org/wiki/Utnapisztim\" target=\"_blank\" rel=\"noopener noreferrer\">Utnapisztim</a> (odpowiednik biblijnego <a href=\"https://pl.wikipedia.org/wiki/Noe\" target=\"_blank\" rel=\"noopener noreferrer\">Noego</a>) i jego żona.", "Ewa": "<b>Ewa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które pierwszy raz pojawia się 2000 lat p.n.e. w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a> jako „Awa” gdzie oznacza „życie”. W języku hebrajskim, który zapożyczył to imię od Sumerów wywodzi się od rdzenia חוה <i>hajja</i> lub hawwa – i również oznacza ‘dająca życie’. Imię wyprowadzane też z arabskiego słowa <i>hajja</i> ‘wąż’.", "Elendil": "Pojawia się w <i><a href=\"https://pl.wikipedia.org/wiki/Silmarillion\" target=\"_blank\" rel=\"noopener noreferrer\">Silmarillionie</a></i>, bardzo często wspominają o nim bohaterowie <i><a href=\"https://pl.wikipedia.org/wiki/W%C5%82adca_Pier%C5%9Bcieni\" target=\"_blank\" rel=\"noopener noreferrer\">Władcy Pierścieni</a></i>. Liczne informacje na jego temat znajdują się w <i>Dodatkach</i> do trzeciego tomu powieści oraz w <i><a href=\"https://pl.wikipedia.org/wiki/Niedoko%C5%84czone_opowie%C5%9Bci\" target=\"_blank\" rel=\"noopener noreferrer\">Niedokończonych opowieściach</a></i>.", "Eleni": "<b>Eleni Tzoka</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ελένη Τζόκα) z domu <b>Milopulu</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Μυλοπούλου) (ur. <a href=\"https://pl.wikipedia.org/wiki/27_kwietnia\" target=\"_blank\" rel=\"noopener noreferrer\">27 kwietnia</a> <a href=\"https://pl.wikipedia.org/wiki/1956\" target=\"_blank\" rel=\"noopener noreferrer\">1956</a> w <a href=\"https://pl.wikipedia.org/wiki/Bielawa\" target=\"_blank\" rel=\"noopener noreferrer\">Bielawie</a>) – <a href=\"https://pl.wikipedia.org/wiki/Polacy\" target=\"_blank\" rel=\"noopener noreferrer\">polska</a> <a href=\"https://pl.wikipedia.org/wiki/Piosenkarz\" target=\"_blank\" rel=\"noopener noreferrer\">piosenkarka</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Grecy\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, <a href=\"https://pl.wikipedia.org/wiki/Autor\" target=\"_blank\" rel=\"noopener noreferrer\">autorka tekstów</a> i <a href=\"https://pl.wikipedia.org/wiki/Kompozytor\" target=\"_blank\" rel=\"noopener noreferrer\">kompozytorka</a>. Wykonuje utwory w języku: polskim, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckim</a> i angielskim.", "Efendi": "<b>Efendi</b> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_turecki\" target=\"_blank\" rel=\"noopener noreferrer\">turecki</a> tytuł oznaczający <i>pana</i>, <i>władcę</i>. Pierwotnie odnosił się do sułtana, potem do urzędników wysokiego szczebla jak <a href=\"https://pl.wikipedia.org/wiki/Bej\" target=\"_blank\" rel=\"noopener noreferrer\">bej</a> lub <a href=\"https://pl.wikipedia.org/wiki/Pasza_(urz%C4%85d)\" target=\"_blank\" rel=\"noopener noreferrer\">pasza</a>, następnie do osób posiadających wyuczony zawód i osób piśmiennych. Zniesiony w 1934 roku. Współcześnie używany po nazwisku tytuł grzecznościowy odpowiadający polskiemu „pan”.", "Elżbieta": "<b>Elżbieta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a> wywodzące się od hebrajskiego słowa אלשבת <i>eliszewa</i> („Bóg mą przysięgą”). Zdrobnienia to Ela, Elka, Elcia, Elunia, Elżbietka, Elżunia, a pochodne to <a href=\"https://pl.wikipedia.org/wiki/Halszka\" target=\"_blank\" rel=\"noopener noreferrer\">Halszka</a>, Halżbieta, Alżbieta, <a href=\"https://pl.wikipedia.org/wiki/Izabela\" target=\"_blank\" rel=\"noopener noreferrer\">Izabela</a>, Liza, Elza (germ.), Eliza.", "Edyta": "<b>Edyta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskiego</a>. Imię pochodzące od staroangielskiego <i><b>ead</b></i> i starogermańskiego <i><b>od</b></i>- pomyślność, szczęście, oraz od staroangielskiego <i><b>gyth</b></i> i starogermańskiego <i><b>gunt</b></i> – walka.", "Eliza": "<b>Eliza</b> – skrócona forma <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <i>Elisabeth</i>, czyli po polsku <a href=\"https://pl.wikipedia.org/wiki/El%C5%BCbieta\" target=\"_blank\" rel=\"noopener noreferrer\">Elżbiety</a>. W Polsce jest znane od <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII wieku</a> jako imię literackie, a gwałtowną popularność zyskało w <a href=\"https://pl.wikipedia.org/wiki/Lata_70._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">latach 70 XX wieku</a>.", "Eugenia": "<b>Eugenia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeńska forma męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Eugeniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Eugeniusz</a>.", "Elwira": "<b>Elwira</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii. Na ogół przypisywane jest jej pochodzenie z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gocki\" target=\"_blank\" rel=\"noopener noreferrer\">gockiego</a> i znaczenie „prawdziwie szlachetna”, ale mogłoby też oznaczać „opiekunka wszystkich”. Według najnowszych publikacji naukowych imię to wywodzi się jednak z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">języka arabskiego</a>, a przedostało się do Polski za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">języka hiszpańskiego</a>, podobnie jak <a href=\"https://pl.wikipedia.org/wiki/Eleonora\" target=\"_blank\" rel=\"noopener noreferrer\">Eleonora</a>.", "Eleonora": "<b>Eleonora</b> – imię żeńskie nieustalonego pochodzenia; być może <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> (może od <i>el</i> – „Bóg” oraz <i>or</i> – „światło”; czyli „Bóg mi światłem”), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> lub <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (od <i>eleo</i> – „lituję się”).", "Estera": "<b>Estera</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Nosiła je <a href=\"https://pl.wikipedia.org/wiki/Estera_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">tytułowa bohaterka</a> <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Estery\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Estery</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;אֶסְתֵּר&#8206;). Imię to wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroperski\" target=\"_blank\" rel=\"noopener noreferrer\">staroperskiego</a> słowa <i>setarah</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">pers.</a>&#160;&#8207;ستاره&#8206;) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Gwiazda\" target=\"_blank\" rel=\"noopener noreferrer\">gwiazda</a>”; może mieć również rodowód akadyjski – od imienia bogini <a href=\"https://pl.wikipedia.org/wiki/Isztar\" target=\"_blank\" rel=\"noopener noreferrer\">Isztar</a>.", "Elena": "<b>Helena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἑλένη oznaczającego „blask Księżyca”. W Polsce po raz pierwszy imię to odnotowano w 1272.", "Eryka": "<b>Eryka</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Eryk\" target=\"_blank\" rel=\"noopener noreferrer\">Eryk</a>, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>.", "Edwarda": "<b>Edwarda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia angielskiego, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Edward\" target=\"_blank\" rel=\"noopener noreferrer\">Edward</a>. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">języku staroangielskim</a> słowo <i>ead</i> oznacza „pomyślność, dobrobyt, szczęście”, a także „obrońca”.", "Elfryda": "<b>Elfryda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające „moc elfa” (chroniona przez <a href=\"https://pl.wikipedia.org/wiki/Elf_(fantastyka)\" target=\"_blank\" rel=\"noopener noreferrer\">elfy</a>), a złożone z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">staroangielskiego</a> słowa <i>ælf</i> połączonego z <i>þryð</i> – „siła, moc”.", "Eulalia": "<b>Eulalia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się ze złożenia słów εὐ („dobrze”) i λαλεῖν („mówić”), oznaczającego „dobrze mówiąca” lub „elokwentna”.", "Edeltrauda": "<b>Edeltruda</b>, <b>Edeltrauda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">staro-wysoko-niemieckiego</a>, nienotowane w Polsce w średniowieczu; obecnie występuje w zauważalnym stopniu w Polsce na obszarach zamieszkiwanych przez mniejszość niemiecką. Imię to powstało z połączenia członów <i>adal</i> – 'szlachetny ród' oraz <i>trud</i> – 'siła, potęga' i stanowi późniejszą wersję niemieckiego imienia <i>Adeltraud</i>.", "Emanuela": "<b>Emanuela</b>, <b>Manuela</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Emanuel\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuel</a>, pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języka hebrajskiego</a>.", "Erna": "<b>Erna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Skrócona forma imion <a href=\"https://pl.wikipedia.org/wiki/Ernesta\" target=\"_blank\" rel=\"noopener noreferrer\">Ernesta</a> i <a href=\"https://pl.wikipedia.org/wiki/Ernestyna\" target=\"_blank\" rel=\"noopener noreferrer\">Ernestyna</a>.", "Emila": "Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Emil\" target=\"_blank\" rel=\"noopener noreferrer\">Emil</a>, <a href=\"https://pl.wikipedia.org/wiki/Emilian\" target=\"_blank\" rel=\"noopener noreferrer\">Emilian</a>.", "Eunika": "<b>Eunika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, składające się ze słów <i>eu</i> „dobrze” i <i>níke</i> „zwycięstwo”. Imię rozsławił <a href=\"https://pl.wikipedia.org/wiki/Henryk_Sienkiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Henryk Sienkiewicz</a>, który nadał je w powieści <i><a href=\"https://pl.wikipedia.org/wiki/Quo_vadis\" target=\"_blank\" rel=\"noopener noreferrer\">Quo vadis</a></i> Eunice, ukochanej Petroniusza.", "Ema": "<b>Ema</b>, <b>Emma</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia germańskiego, od imienia <i>Erma</i>, które było skróconą formą imion zaczynających się od <i>Erm-</i> i <i>Irm-</i>.", "Ernestyna": "<b>Ernestyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Ernest\" target=\"_blank\" rel=\"noopener noreferrer\">Ernest</a> oznaczającego „poważny, stanowczy”. W Kościele katolickim istnieją dwie patronki tego imienia.", "Eufemia": "<b>Eufemia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Złożone jest z elementów εὐ- („dobry”) i φήμη („wróżba”), i oznacza „dobrze wróżąca”, „pomyślnie wróżąca”, „przychylna”. W Polsce imię to zanotowano w XIII wieku. Nosiły je m.in. księżniczki piastowskie. Imię zdrabniano jako Ofka.", "Elmira": "<b>Elmira</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niejasnej etymologii.", "Erwina": "<b>Erwina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Erwin\" target=\"_blank\" rel=\"noopener noreferrer\">Erwin</a>.", "Edmunda": "<b>Edmunda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Edmund\" target=\"_blank\" rel=\"noopener noreferrer\">Edmund</a>. Wywodzi się od słowa oznaczającego \"obrończyni, opiekunka majątku, bogactwa\".", "Eufrozyna": "<b>Eufrozyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>euphrosýne</i> oznaczającego radość. Eufrosyne była jedną z mitologicznych <a href=\"https://pl.wikipedia.org/wiki/Charyty\" target=\"_blank\" rel=\"noopener noreferrer\">Gracji</a>, bogiń wdzięku i radości.", "Eligia": "<b>Eligia</b> – żeńska wersja <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Eligiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Eligiusz</a>, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego \"wybrany\".", "Edwina": "<b>Edwina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Edwin\" target=\"_blank\" rel=\"noopener noreferrer\">Edwin</a>. Wywodzi się od słów oznaczających \"pomyślność\", \"szczęście\" i \"przyjaciel\". Patronem tego imienia jest św. Edwin, król Northumbrii.", "Emiliana": "<b>Emiliana, Emilianna</b> - żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Emilian\" target=\"_blank\" rel=\"noopener noreferrer\">Emilian</a>. Patronką tego imienia w Kościele katolickim jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ta_Emiliana\" target=\"_blank\" rel=\"noopener noreferrer\">św. Emiliana</a>, żyjąca w <a href=\"https://pl.wikipedia.org/wiki/VI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VI wieku</a>.", "Emine": "W rejonie przylądka Emine są ruiny <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznego</a> <a href=\"https://pl.wikipedia.org/wiki/Monaster\" target=\"_blank\" rel=\"noopener noreferrer\">monasteru</a> i twierdzy Emona. Jej nazwa pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytna_Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">starogreckiej</a> nazwy Starej Płaniny - <i>Aemon</i> (<i>Αίμος</i> - Aemos). Tę samą nazwę nosi też pobliska wieś <a href=\"https://pl.wikipedia.org/wiki/Emona\" target=\"_blank\" rel=\"noopener noreferrer\">Emona</a>.", "Euzebia": "<b>Euzebia</b> – żeński odpowiednik męskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Euzebiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Euzebiusz</a>. Wywodzi się od greckiego wyrazu <i>eusébeia</i> – pobożność.", "Ernesta": "<b>Ernesta</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Ernest\" target=\"_blank\" rel=\"noopener noreferrer\">Ernest</a>.", "Evangelina": "<b>Ewangelina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Powstało ze złożenia <i>ευ</i> - „dobry” oraz <i>αγγελμα (angelma)</i> - „wiadomość, wieść, przesłanie” i oznacza „dobra nowina”.", "Elissa": "Według przekazu starożytnych historyków <a href=\"https://pl.wikipedia.org/wiki/Timajos\" target=\"_blank\" rel=\"noopener noreferrer\">Timajosa</a> i <a href=\"https://pl.wikipedia.org/wiki/Pompejusz_Trogus\" target=\"_blank\" rel=\"noopener noreferrer\">Pompejusza Trogusa</a> w IX wieku p.n.e. z <a href=\"https://pl.wikipedia.org/wiki/Tyr_(miasto)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyru</a> miała zbiec grupa jego mieszkańców na północne wybrzeża <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Afryki</a>, niedaleko <a href=\"https://pl.wikipedia.org/wiki/Fenicja\" target=\"_blank\" rel=\"noopener noreferrer\">fenickiej</a> kolonii <a href=\"https://pl.wikipedia.org/wiki/Utyka\" target=\"_blank\" rel=\"noopener noreferrer\">Utyki</a>. Przywódczynią kolonistów była Dydona (zwana też Eliszą lub Elissą), która uciekła, ponieważ jej brat <a href=\"https://pl.wikipedia.org/wiki/Pigmalion_z_Tyru\" target=\"_blank\" rel=\"noopener noreferrer\">Pigmalion</a> zabił jej męża Acharbasa (w <i>Eneidzie</i>: Sycheusza lub Sycheja). W jej otoczeniu znajdowali się bogaci Fenicjanie (nie jest wyjaśnione dlaczego, prawdopodobnie to oni uciekali), w drodze zatrzymali się na <a href=\"https://pl.wikipedia.org/wiki/Cypr_(wyspa)\" target=\"_blank\" rel=\"noopener noreferrer\">Cyprze</a>, skąd zabrano arcykapłana i dużą grupę dziewcząt. Gdy wysiedli na ląd, otoczyli ich miejscowi <a href=\"https://pl.wikipedia.org/wiki/Numidia\" target=\"_blank\" rel=\"noopener noreferrer\">Numidyjczycy</a> i zaczęły się pertraktacje. Ostatecznie Dydonie użyczono takiego skrawka ziemi na wybrzeżu, jaki obejmie skóra wołu. Dydona pocięła więc ją na wąskie paski i objęła nimi miejsce, na którym wzniesiono Byrsę (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βύρσα – skóra) – <a href=\"https://pl.wikipedia.org/wiki/Akropol\" target=\"_blank\" rel=\"noopener noreferrer\">akropol</a> Kartaginy. Imię Elissy zostało zmienione przez tubylców na Dydona, co oznacza „wędrowniczka”. Wcześniejsze imię pochodzi od fenickiego bóstwa <a href=\"https://pl.wikipedia.org/wiki/El\" target=\"_blank\" rel=\"noopener noreferrer\">Ela</a> – być może więc Elissa była w Fenicji jego kapłanką.", "Edeltruda": "<b>Edeltruda</b>, <b>Edeltrauda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">staro-wysoko-niemieckiego</a>, nienotowane w Polsce w średniowieczu; obecnie występuje w zauważalnym stopniu w Polsce na obszarach zamieszkiwanych przez mniejszość niemiecką. Imię to powstało z połączenia członów <i>adal</i> – 'szlachetny ród' oraz <i>trud</i> – 'siła, potęga' i stanowi późniejszą wersję niemieckiego imienia <i>Adeltraud</i>.", "Eter": "<b>Eter</b> (<a href=\"https://pl.wikipedia.org/wiki/Alfabet_deseret\" target=\"_blank\" rel=\"noopener noreferrer\">deseret</a> 𐐀𐐛𐐇𐐡, 𐐁𐐛𐐇𐐡) – imię męskie występujące w wyznaniach należących do <a href=\"https://pl.wikipedia.org/wiki/Ruch_%C5%9Bwi%C4%99tych_w_dniach_ostatnich\" target=\"_blank\" rel=\"noopener noreferrer\">ruchu świętych w dniach ostatnich</a> (mormonów).", "Eustachia": "<b>Eustachia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia greckiego, żeński odpowiednik imion <a href=\"https://pl.wikipedia.org/wiki/Eustachy\" target=\"_blank\" rel=\"noopener noreferrer\">Eustachy</a> i <a href=\"https://pl.wikipedia.org/wiki/Eustachiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Eustachiusz</a>.", "Ewangelina": "<b>Ewangelina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Powstało ze złożenia <i>ευ</i> - „dobry” oraz <i>αγγελμα (angelma)</i> - „wiadomość, wieść, przesłanie” i oznacza „dobra nowina”.", "Edda": "<b>Edda</b> – włoska forma norweskiego lub szwedzkiego <i>Hedda</i>, co stanowi zdrobnienie od <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Jadwiga\" target=\"_blank\" rel=\"noopener noreferrer\">Hedwig</a>, czyli germańskiej formy imienia <a href=\"https://pl.wikipedia.org/wiki/Jadwiga\" target=\"_blank\" rel=\"noopener noreferrer\">Jadwiga</a>. Edda jest przede wszystkim jednak znana jako część nazwy <i><a href=\"https://pl.wikipedia.org/wiki/Edda_starsza\" target=\"_blank\" rel=\"noopener noreferrer\">Eddy poetyckiej</a></i>, najstarszego zabytku <a href=\"https://pl.wikipedia.org/wiki/Literatura_islandzka\" target=\"_blank\" rel=\"noopener noreferrer\">piśmiennictwa islandzkiego</a>.", "Eglė": "<b>Eglė</b> lub <b>Eglija</b> – żeńskie imię bałtyckie. Z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">lit.</a> <i>eglė</i>, co znaczy <i>świerk</i>.", "Emiko": "<b>Emiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;えみこ, エミコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Ewarysta": "<b>Ewarysta</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Ewaryst\" target=\"_blank\" rel=\"noopener noreferrer\">Ewaryst</a>.", "Eudoksja": "<b>Eudoksja</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ευδοξία) – imię żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik męskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Eudoksjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Eudoksjusz</a>. Oznacza „dobra sława”, od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;εὐ (<i>ew</i>, „dobrze”) i δόξα (doksa, „sława, chwała”).", "Ewalda": "<b>Ewalda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Ewald\" target=\"_blank\" rel=\"noopener noreferrer\">Ewald</a>. Wywodzi się ze złożenia słów <i>eo</i> – „prawo” i <i>wald</i> – „rządzić”, „panować”. Jego znaczenie można interpretować jako „panująca sprawiedliwie, w zgodzie z prawem”. Patronami tego imienia są bracia śwśw. Ewald Biały i Ewald Czarny (<a href=\"https://pl.wikipedia.org/wiki/VII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VII wiek</a>), wspominani 3 października.", "Erazma": "<b>Erazma</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Erazm\" target=\"_blank\" rel=\"noopener noreferrer\">Erazm</a>, wywodzącego się od greckiego <i>Erasmōs</i>, co oznacza „godny miłości, miły”.", "Etsuko": "<b>Etsuko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;えつこ, エツコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Eriko": "<b>Eriko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;えりこ, エリコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Eiko": "<b>Eiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;えいこ, エイコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Eta": "<b>Eta</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;ἦτα, pisana <b>Ηη</b>) – siódma <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">litera</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu greckiego</a> oznaczająca w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starogrecki\" target=\"_blank\" rel=\"noopener noreferrer\">języku starogreckim</a> długą „ē” (długie „e”). W greckim systemie liczbowym oznacza liczbę <a href=\"https://pl.wikipedia.org/wiki/8_(liczba)\" target=\"_blank\" rel=\"noopener noreferrer\">8</a>.", "Ewdokia": "<b>Eudokia</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Εὐδοκία) – imię żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;ευδοκεω (<i>eudokeo</i>), co według niektórych źródeł oznacza „być bardzo zadowolonym, być zadowolonym”, od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;ευ – „dobra” i δοκεω (<i>dokeo</i>) – „myśleć, wyobrażać sobie, przypuszczać”, według innych – \"życzliwość\". Jej ludową formą rosyjską jest <i><b>Awdotia</b></i>. W polskiej literaturze Eudokia jest utożsamiana z <a href=\"https://pl.wikipedia.org/wiki/Eudoksja_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Eudoksją</a>.", "Epifania": "<b>Epifania</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Epifaniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Epifaniusz</a> lub <a href=\"https://pl.wikipedia.org/wiki/Epifani\" target=\"_blank\" rel=\"noopener noreferrer\">Epifani</a>, pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>epifaneia</i> – objawienie, ukazanie się.", "Egle": "<b>Eglė</b> lub <b>Eglija</b> – żeńskie imię bałtyckie. Z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">lit.</a> <i>eglė</i>, co znaczy <i>świerk</i>.", "Ekspedyta": "<b>Ekspedyta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od czasownika <i>expedio</i> – \"uwolnić, wyzwolić z więzów\". <i>Expeditus</i> zaś oznacza \"wolny, lekko ubrany, lekkozbrojny, szybki, zwinny\". Jest to żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Ekspedyt\" target=\"_blank\" rel=\"noopener noreferrer\">Ekspedyt</a>, a patronem tego imienia jest św. Ekspedyt (św. Wierzyn), patron spraw pilnych, nie cierpiących zwłoki.", "Ermelinda": "<b>Ermelinda</b>, Irmelinda, <i>Hermelinda</i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, składające się z członów: <i>Ermen–</i>, od germ. <i>ermana</i> („wielki, wszechogarniający” – imię <a href=\"https://pl.wikipedia.org/wiki/P%C3%B3%C5%82b%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">półboga</a> germańskiego) oraz <i>lind</i> – „giętka, miękka, łagodna, przyjazna”, może też „<a href=\"https://pl.wikipedia.org/wiki/Tarcza_(uzbrojenie)\" target=\"_blank\" rel=\"noopener noreferrer\">tarcza</a> z drewna <a href=\"https://pl.wikipedia.org/wiki/Lipa\" target=\"_blank\" rel=\"noopener noreferrer\">lipowego</a>”.", "Eustazja": "<b>Eustazja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, stanowiące żeński odpowiednik imion <a href=\"https://pl.wikipedia.org/wiki/Eustazjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Eustazjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Eustazy\" target=\"_blank\" rel=\"noopener noreferrer\">Eustazy</a>. Wśród patronów tego imienia – św. Eustazjusz, biskup <a href=\"https://pl.wikipedia.org/wiki/Neapol\" target=\"_blank\" rel=\"noopener noreferrer\">Neapolu</a>.", "Ewodia": "<b>Ewodia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Ewodiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Ewodiusz</a>, złożonego z członów <i>eu-</i> (\"dobry\") i <i>hodos-</i> (\"droga\"), i oznaczającego \"człowiek dobrej drogi, mający powodzenie\". Ewodia jest wspomniana w <a href=\"https://pl.wikipedia.org/wiki/List_do_Filipian\" target=\"_blank\" rel=\"noopener noreferrer\">liście św. Pawła do Filipian</a>. <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bci%C3%B3%C5%82_katolicki\" target=\"_blank\" rel=\"noopener noreferrer\">Kościół katolicki</a> notuje sześciu świętych Ewodiuszów — patronów tego imienia.", "Elegia": "W poezji starogreckiej, skąd wywodzi się ten gatunek, obowiązkowa była dla niego forma wierszowa <a href=\"https://pl.wikipedia.org/wiki/Dystych_elegijny\" target=\"_blank\" rel=\"noopener noreferrer\">dystychu elegijnego</a>. Mistrzem elegii w poezji starorzymskiej był <a href=\"https://pl.wikipedia.org/wiki/Owidiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Owidiusz</a>, po nim gatunek ten uprawiali z powodzeniem <a href=\"https://pl.wikipedia.org/wiki/John_Milton\" target=\"_blank\" rel=\"noopener noreferrer\">John Milton</a>, <a href=\"https://pl.wikipedia.org/wiki/Johann_Wolfgang_von_Goethe\" target=\"_blank\" rel=\"noopener noreferrer\">Johann Wolfgang von Goethe</a>, <a href=\"https://pl.wikipedia.org/wiki/Aleksandr_Puszkin\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandr Puszkin</a>, <a href=\"https://pl.wikipedia.org/wiki/Rainer_Maria_Rilke\" target=\"_blank\" rel=\"noopener noreferrer\">Rainer Maria Rilke</a>.", "Egidia": "<b>Egidia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik imienia Egidiusz, które funkcjonuje w Polsce przede wszystkim w formie <a href=\"https://pl.wikipedia.org/wiki/Idzi\" target=\"_blank\" rel=\"noopener noreferrer\">Idzi</a>. Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Idzi_z_Saint-Gilles\" target=\"_blank\" rel=\"noopener noreferrer\">św. Idzi</a> i inni święci o tym imieniu. To imię nosiły córki królów szkockich, np. <a href=\"https://pl.wikipedia.org/wiki/Robert_II_Stewart\" target=\"_blank\" rel=\"noopener noreferrer\">Roberta II</a>.", "Eza": "<a href=\"https://pl.wikipedia.org/wiki/Wikipedia:Zastrze%C5%BCenia_dotycz%C4%85ce_poj%C4%99%C4%87_medycznych\" target=\"_blank\" rel=\"noopener noreferrer\">Przeczytaj ostrzeżenie dotyczące informacji medycznych i pokrewnych zamieszczonych w Wikipedii</a>.", "Emerencja": "<b>Emerencja</b>, <b>Emerencjana</b>, <b>Emerencjanna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, o znaczeniu „ta, która się dobrze zasłużyła”. Chrześcijańską patronką tego imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Emerencjana_(m%C4%99czennica)\" target=\"_blank\" rel=\"noopener noreferrer\">Emerencjana</a>, rzymska męczennica.", "Edburga": "<b>Edburga</b> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">staroangielskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, składające się z członów <i>ed–</i> — \"majątek dziedziczny, posiadłość dziedziczna\" i <i>–burg</i> — \"ochrona, opieka\", a oznaczające \"opiekunka posiadłości\". Istnieje sześć świętych patronek tego imienia — wszystkie były angielskimi mniszkami z okresu średniowiecza.", "Edelburga": "<b>Edelburga</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Powstało ono ze staro-wysoko-niemieckich słów <i>adal</i> – 'szlachetny ród' oraz <i>burg</i> o znaczeniu 'ochraniać, chronić'. Wśród świętych – św. Edelburga, królewna, ksieni (<a href=\"https://pl.wikipedia.org/wiki/VIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VIII wiek</a>).", "Emeryka": "<b>Emeryka</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Emeryk\" target=\"_blank\" rel=\"noopener noreferrer\">Emeryk</a>, wywodzącego się ze starogermańskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Amalaryk\" target=\"_blank\" rel=\"noopener noreferrer\">Amalaryk</a>, oznaczającego „władca <a href=\"https://pl.wikipedia.org/wiki/Amalowie\" target=\"_blank\" rel=\"noopener noreferrer\">Amalów</a>” (Amalowie według gockiej legendy to ród królewski pochodzenia boskiego). Człon <i>amal</i> może także oznaczać „gorliwy” lub „dzielny, aktywny”. Emeryka może wywodzić się również z saksońskiego <i>Emmerich</i> i oznaczać „zawsze bogata”."};
